// src/components/payment/Payment.jsx
import { useState, useEffect } from "react";
import './Payment.css';

const AmountForm = ({ amount = 0, transportData }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [paymentData, setPaymentData] = useState(null);
  const [qrCode, setQrCode] = useState("");

  // Auto-submit when amount is provided
  useEffect(() => {
    if (amount && amount >= 10 && amount <= 50000) {
      handleSubmit(amount);
    }
  }, [amount]);

  const handleSubmit = async (submitAmount) => {
    if (!submitAmount || submitAmount < 10 || submitAmount > 50000) {
      setError("Amount must be between ₹10 and ₹50,000");
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      const token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJfaWQiOiI2NzEwODhmZjM4ZGJhNzhhZDY2YjVmZWIiLCJwaG9uZU51bWJlciI6ODgxMDMwMDcyNCwiZW1haWwiOiJzeTI0MTUyN0BnbWFpbC5jb20iLCJyb2xlIjoiY2hhZ2Fuc0VtcGxveWVlMiIsImxvZ2luSWQiOiJmOGUzOWRhOC03MmQ2LTRmNTUtYWJlMC0xM2Q5YWIxMjJmZTkiLCJpYXQiOjE3NjkxNDM0NDUsImV4cCI6MTc3NjkxOTQ0NX0.Y8_yAqXxKhw7Hijfn5zJkHfWDHqijjRyxDom2XwqzFs";
      
      if (!token) {
        setError("Authentication required. Please login.");
        setIsLoading(false);
        return;
      }

      console.log("Sending payment request with amount:", submitAmount);

      const response = await fetch(
        `https://chagans.com/payment/addMoneyTen`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json"
          },
          body: JSON.stringify({
            amount: submitAmount, 
            transportData: {
              ...transportData,
              trackingId: `TRK${Math.floor(100000 + Math.random() * 900000)}`,
            },
            mobile: "7983920962",
            apiType: "API",
          }),
        }
      );

      console.log("Response status:", response.status);
      
      if (!response.ok) {
        const errorText = await response.text();
        console.error("Error response:", errorText);
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      console.log("Payment response data:", data);
      
      if (data.success) {
        setPaymentData(data.data);
        
        // Generate QR Code using the payment data
        // Create a payment URL from the data
        const paymentUrl = data.data.APIURL + "?" + new URLSearchParams({
          PAY_ID: data.data.PAY_ID,
          AMOUNT: data.data.AMOUNT,
          CUST_NAME: data.data.CUST_NAME,
          ORDER_ID: data.data.ORDER_ID,
          HASH: data.data.HASH
        }).toString();
        
        setQrCode(paymentUrl);
        setError(""); // Clear any errors
      } else {
        setError(data.message || "Payment failed. Please try again.");
      }
    } catch (err) {
      console.error('Full payment error:', err);
      setError("Network error. Please check your connection.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="amount-form-container">
      {/* Loading State */}
      {isLoading && (
        <div className="loading-indicator">
          <div className="spinner"></div>
          <p>Processing payment...</p>
        </div>
      )}

      {/* Error Message */}
      {error && (
        <div className="error-message">
          <p>{error}</p>
        </div>
      )}

      {/* Payment Data Display with Real QR Code */}
      {paymentData && (
        <div className="payment-data">
          <h3 style={{textAlign: 'center', marginBottom: '20px'}}>Scan QR Code to Pay</h3>
          
          {/* Amount Display */}
          <div style={{textAlign: 'center', marginBottom: '20px'}}>
            <div style={{fontSize: '14px', color: '#666'}}>Total Amount</div>
            <div style={{fontSize: '28px', fontWeight: 'bold', color: '#16a34a'}}>
              ₹{parseInt(paymentData.AMOUNT)/100}
            </div>
          </div>

          {/* Real QR Code - Using Google Charts API */}
          <div style={{textAlign: 'center', marginBottom: '20px'}}>
            <img 
              src={`https://chart.googleapis.com/chart?chs=250x250&cht=qr&chl=${encodeURIComponent(qrCode)}&choe=UTF-8`}
              alt="Payment QR Code"
              style={{width: '220px', height: '220px', border: '1px solid #ddd', borderRadius: '8px'}}
            />
          </div>

          {/* Payment Details */}
          <div className="payment-details" style={{
            background: '#f3f4f6',
            padding: '15px',
            borderRadius: '8px',
            marginBottom: '15px'
          }}>
            <p style={{margin: '5px 0'}}><strong>Order ID:</strong> {paymentData.ORDER_ID}</p>
            <p style={{margin: '5px 0'}}><strong>Payment ID:</strong> {paymentData.PAY_ID}</p>
            <p style={{margin: '5px 0'}}><strong>Name:</strong> {paymentData.CUST_NAME}</p>
          </div>

          {/* Instructions */}
          <div style={{
            background: '#e6f7ff',
            padding: '15px',
            borderRadius: '8px',
            border: '1px solid #91d5ff'
          }}>
            <p style={{margin: '0 0 10px 0', fontWeight: 'bold'}}>📱 How to Pay:</p>
            <ol style={{margin: '0', paddingLeft: '20px'}}>
              <li>Open any UPI app (Google Pay, PhonePe, PayTM)</li>
              <li>Scan this QR code</li>
              <li>Verify the amount: ₹{parseInt(paymentData.AMOUNT)/100}</li>
              <li>Complete the payment</li>
            </ol>
          </div>
        </div>
      )}
    </div>
  );
};

export default AmountForm;
